{"code": "import json

lit = var_functions.query_db:34
perf = var_functions.query_db:30

perf_ids = set()
for row in perf:
    perf_ids.add(row['book_id_num'])

matches = []
for book in lit:
    book_id = book['book_id']
    num_id = int(book_id.split('_')[1])
    if num_id in perf_ids:
        review_info = None
        for r in perf:
            if r['book_id_num'] == num_id:
                review_info = r
                break
        matches.append({
            'book_id': book_id,
            'title': book['title'],
            'avg_rating': 5.0,
            'review_count': review_info['review_count'] if review_info else 0
        })

print('__RESULT__:')
print(json.dumps(matches, indent=2))"}

